     3Ôćĺimport (
     4Ôćĺ	"context"
     5Ôćĺ	"encoding/json"
     6Ôćĺ	"fmt"
     7Ôćĺ	"log/slog"
     8Ôćĺ	"net/http"
     9Ôćĺ	"regexp"
    10Ôćĺ	"strings"
    11Ôćĺ	"time"
    12Ôćĺ
    13Ôćĺ	"github.com/riverqueue/river"
    14Ôćĺ	"github.com/sentioxyz/changelogue/internal/models"
    15Ôćĺ	"github.com/sentioxyz/changelogue/internal/queue"
    16Ôćĺ)
    17Ôćĺ
    18Ôćĺ// NotifyStore is the data access interface required by the notification worker.
    19Ôćĺtype NotifyStore interface {
    20Ôćĺ	GetRelease(ctx context.Context, id string) (*models.Release, error)
    21Ôćĺ	GetSource(ctx context.Context, id string) (*models.Source, error)
    22Ôćĺ	ListSourceSubscriptions(ctx context.Context, sourceID string) ([]models.Subscription, error)
    23Ôćĺ	GetChannel(ctx context.Context, id string) (*models.NotificationChannel, error)
    24Ôćĺ	GetProject(ctx context.Context, id string) (*models.Project, error)
    25Ôćĺ	GetPreviousRelease(ctx context.Context, sourceID string, beforeVersion string) (*models.Release, error)
    26Ôćĺ	EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error
    27Ôćĺ	CreateReleaseTodo(ctx context.Context, releaseID string) (string, error)
    28Ôćĺ}
    29Ôćĺ
    30Ôćĺ// NotifyWorker is a River worker that processes NotifyJobArgs.
    31Ôćĺ// It looks up the release, finds all source-level subscriptions, resolves
    32Ôćĺ// the notification channel for each, and dispatches via the appropriate sender.
    33Ôćĺ// After sending notifications, it checks the project's agent rules and
    34Ôćĺ// auto-triggers an agent run if the version criteria are met.
    35Ôćĺtype NotifyWorker struct {
    36Ôćĺ	river.WorkerDefaults[queue.NotifyJobArgs]
    37Ôćĺ	store     NotifyStore
    38Ôćĺ	senders   map[string]Sender
    39Ôćĺ	publicURL string // base URL for internal Changelogue links (e.g. "https://changelogue.example.com")
    40Ôćĺ}
    41Ôćĺ
    42Ôćĺ// NewSenders returns the default sender map for all notification channel types.
    43Ôćĺfunc NewSenders() map[string]Sender {
    44Ôćĺ	return map[string]Sender{
    45Ôćĺ		"webhook": &WebhookSender{Client: &http.Client{Timeout: 10 * time.Second}},
    46Ôćĺ		"slack":   &SlackSender{Client: &http.Client{Timeout: 10 * time.Second}},
    47Ôćĺ		"discord": &DiscordSender{Client: &http.Client{Timeout: 10 * time.Second}},
    48Ôćĺ		"email":   &EmailSender{},
    49Ôćĺ	}
    50Ôćĺ}
    51Ôćĺ
    52Ôćĺ// NewNotifyWorker creates a NotifyWorker with default senders for webhook, Slack, and Discord.
    53Ôćĺfunc NewNotifyWorker(store NotifyStore, publicURL string) *NotifyWorker {
    54Ôćĺ	return &NotifyWorker{
    55Ôćĺ		store:     store,
    56Ôćĺ		senders:   NewSenders(),
    57Ôćĺ		publicURL: strings.TrimRight(publicURL, "/"),
    58Ôćĺ	}
    59Ôćĺ}
    60Ôćĺ
    61Ôćĺ// VersionPassesFilter returns true if the version string passes the source's
    62Ôćĺ// include/exclude regex filters. When both are nil the version always passes.
    63Ôćĺfunc VersionPassesFilter(version string, include, exclude *string) bool {
    64Ôćĺ	if include != nil && *include != "" {
    65Ôćĺ		matched, err := regexp.MatchString(*include, version)
    66Ôćĺ		if err != nil || !matched {
    67Ôćĺ			return false
    68Ôćĺ		}
    69Ôćĺ	}
    70Ôćĺ	if exclude != nil && *exclude != "" {
    71Ôćĺ		matched, err := regexp.MatchString(*exclude, version)
    72Ôćĺ		if err != nil || matched {
    73Ôćĺ			return false
    74Ôćĺ		}
    75Ôćĺ	}
    76Ôćĺ	return true
    77Ôćĺ}
    78Ôćĺ
    79Ôćĺ// Work processes a notify job: fetches the release, resolves subscriptions,
    80Ôćĺ// sends notifications to all matching channels, and checks agent rules to
    81Ôćĺ// auto-trigger agent runs when version criteria are met.
    82Ôćĺfunc (w *NotifyWorker) Work(ctx context.Context, job *river.Job[queue.NotifyJobArgs]) error {
    83Ôćĺ	release, err := w.store.GetRelease(ctx, job.Args.ReleaseID)
    84Ôćĺ	if err != nil {
    85Ôćĺ		return fmt.Errorf("get release: %w", err)
    86Ôćĺ	}
    87Ôćĺ
    88Ôćĺ	// Check source version filters ÔÇö skip entirely if filtered out.
    89Ôćĺ	source, err := w.store.GetSource(ctx, job.Args.SourceID)
    90Ôćĺ	if err != nil {
    91Ôćĺ		return fmt.Errorf("get source: %w", err)
    92Ôćĺ	}
    93Ôćĺ	if !VersionPassesFilter(release.Version, source.VersionFilterInclude, source.VersionFilterExclude) {
    94Ôćĺ		slog.Debug("release filtered by version filter", "version", release.Version, "source_id", job.Args.SourceID)
    95Ôćĺ		return nil
    96Ôćĺ	}
    97Ôćĺ
    98Ôćĺ	// Check exclude_prereleases ÔÇö skip if source excludes prereleases and this is one.
    99Ôćĺ	if source.ExcludePrereleases {
   100Ôćĺ		var rawData map[string]interface{}
   101Ôćĺ		if err := json.Unmarshal(release.RawData, &rawData); err == nil {
   102Ôćĺ			if prerelease, _ := rawData["prerelease"].(string); prerelease == "true" {
   103Ôćĺ				slog.Debug("release filtered by exclude_prereleases", "version", release.Version, "source_id", job.Args.SourceID)
   104Ôćĺ				return nil
   105Ôćĺ			}
   106Ôćĺ		}
   107Ôćĺ	}
   108Ôćĺ
   109Ôćĺ	// Create a TODO for this release (idempotent ÔÇö safe for retries).
   110Ôćĺ	todoID, todoErr := w.store.CreateReleaseTodo(ctx, release.ID)
   111Ôćĺ	if todoErr != nil {
   112Ôćĺ		slog.Error("create release todo failed", "release_id", release.ID, "err", todoErr)
   113Ôćĺ		// Continue ÔÇö notification delivery is primary responsibility.
   114Ôćĺ	}
   115Ôćĺ
   116Ôćĺ	subs, err := w.store.ListSourceSubscriptions(ctx, job.Args.SourceID)
   117Ôćĺ	if err != nil {
   118Ôćĺ		return fmt.Errorf("list subscriptions: %w", err)
   119Ôćĺ	}
   120Ôćĺ
   121Ôćĺ	for _, sub := range subs {
   122Ôćĺ		ch, err := w.store.GetChannel(ctx, sub.ChannelID)
   123Ôćĺ		if err != nil {
   124Ôćĺ			slog.Error("get channel failed", "channel_id", sub.ChannelID, "err", err)
   125Ôćĺ			continue
   126Ôćĺ		}
   127Ôćĺ
   128Ôćĺ		sender, ok := w.senders[ch.Type]
   129Ôćĺ		if !ok {
   130Ôćĺ			slog.Warn("unknown channel type", "type", ch.Type)
   131Ôćĺ			continue
   132Ôćĺ		}
   133Ôćĺ
   134Ôćĺ		// Build title with project name if available.
   135Ôćĺ		title := release.Version
   136Ôćĺ		if release.ProjectName != "" {
   137Ôćĺ			title = release.ProjectName
   138Ôćĺ		}
   139Ôćĺ
   140Ôćĺ		msg := Notification{
   141Ôćĺ			Title:       title,
   142Ôćĺ			Body:        string(release.RawData),
   143Ôćĺ			Version:     release.Version,
   144Ôćĺ			ProjectName: release.ProjectName,
   145Ôćĺ			Provider:    release.Provider,
   146Ôćĺ			Repository:  release.Repository,
   147Ôćĺ			SourceURL:   ProviderURL(release.Provider, release.Repository, release.Version),
   148Ôćĺ		}
   149Ôćĺ		if w.publicURL != "" {
   150Ôćĺ			msg.ReleaseURL = fmt.Sprintf("%s/releases/%s", w.publicURL, release.ID)
   151Ôćĺ		}
   152Ôćĺ		if todoID != "" {
   153Ôćĺ			msg.TodoID = todoID
   154Ôćĺ			msg.PublicURL = w.publicURL
   155Ôćĺ		}
   156Ôćĺ
   157Ôćĺ		if err := sender.Send(ctx, ch, msg); err != nil {
   158Ôćĺ			slog.Error("send notification failed", "channel", ch.Name, "err", err)
   159Ôćĺ		}
   160Ôćĺ	}
   161Ôćĺ
   162Ôćĺ	// Check agent rules and auto-trigger if criteria are met.
   163Ôćĺ	w.checkAgentRules(ctx, release, source)
   164Ôćĺ
   165Ôćĺ	return nil
   166Ôćĺ}
   167Ôćĺ
   168Ôćĺ// checkAgentRules evaluates the project's agent rules against the new release
   169Ôćĺ// and the previous release for this source. If any rule matches, an agent run
   170Ôćĺ// is enqueued. Errors are logged but do not fail the job ÔÇö notification delivery
   171Ôćĺ// is the primary responsibility.
   172Ôćĺfunc (w *NotifyWorker) checkAgentRules(ctx context.Context, release *models.Release, source *models.Source) {
   173Ôćĺ	project, err := w.store.GetProject(ctx, source.ProjectID)
   174Ôćĺ	if err != nil {
   175Ôćĺ		slog.Error("get project for agent rules", "project_id", source.ProjectID, "err", err)
   176Ôćĺ		return
   177Ôćĺ	}
   178Ôćĺ
   179Ôćĺ	// Parse the project's agent_rules JSON.
   180Ôćĺ	var rules models.AgentRules
   181Ôćĺ	if len(project.AgentRules) > 0 {
   182Ôćĺ		if err := json.Unmarshal(project.AgentRules, &rules); err != nil {
   183Ôćĺ			slog.Error("unmarshal agent rules", "project_id", project.ID, "err", err)
   184Ôćĺ			return
   185Ôćĺ		}
   186Ôćĺ	}
   187Ôćĺ
   188Ôćĺ	// Determine the previous version for comparison.
   189Ôćĺ	var previousVersion string
   190Ôćĺ	prev, err := w.store.GetPreviousRelease(ctx, source.ID, release.Version)
   191Ôćĺ	if err != nil {
   192Ôćĺ		slog.Error("get previous release for agent rules", "source_id", source.ID, "err", err)
   193Ôćĺ		return
   194Ôćĺ	}
   195Ôćĺ	if prev != nil {
   196Ôćĺ		previousVersion = prev.Version
   197Ôćĺ	}
   198Ôćĺ
   199Ôćĺ	if CheckAgentRules(&rules, release.Version, previousVersion) {
   200Ôćĺ		trigger := fmt.Sprintf("auto:version:%s", release.Version)
   201Ôćĺ		if err := w.store.EnqueueAgentRun(ctx, source.ProjectID, trigger, release.Version); err != nil {
   202Ôćĺ			slog.Error("enqueue agent run", "project_id", source.ProjectID, "err", err)
   203Ôćĺ		} else {
   204Ôćĺ			slog.Info("agent run triggered by version rules",
   205Ôćĺ				"project_id", source.ProjectID,
   206Ôćĺ				"version", release.Version,
   207Ôćĺ				"previous_version", previousVersion,
   208Ôćĺ			)
   209Ôćĺ		}
   210Ôćĺ	}
   211Ôćĺ}
