    11Ôćĺ// CheckAgentRules evaluates the agent rules against the new and previous version
    12Ôćĺ// strings. Returns true if any rule matches and an agent run should be triggered.
    13Ôćĺfunc CheckAgentRules(rules *models.AgentRules, newVersion, previousVersion string) bool {
    14Ôćĺ	if rules == nil {
    15Ôćĺ		return false
    16Ôćĺ	}
