    19Ôćĺ	oldMajor, oldMinor, _ := parseVersion(previousVersion)
    20Ôćĺ
    21Ôćĺ	if rules.OnMajorRelease && newMajor > oldMajor {
    22Ôćĺ		return true
    23Ôćĺ	}
    24Ôćĺ	if rules.OnMinorRelease && (newMajor > oldMajor || newMinor > oldMinor) {
    25Ôćĺ		return true
    26Ôćĺ	}
    27Ôćĺ	if rules.OnSecurityPatch && isSecurityPatch(newVersion) {
    28Ôćĺ		return true
