    38Ôćĺ// parseVersion extracts major, minor, patch integers from a version string.
    39Ôćĺ// It tolerates a leading "v" prefix and pre-release suffixes (e.g. "-security").
    40Ôćĺfunc parseVersion(v string) (major, minor, patch int) {
