    46Ôćĺ	if len(parts) >= 2 {
    47Ôćĺ		minor, _ = strconv.Atoi(parts[1])
    48Ôćĺ	}
    49Ôćĺ	if len(parts) >= 3 {
    50Ôćĺ		// Strip pre-release suffix (e.g. "4-security" -> "4")
    51Ôćĺ		patchStr := strings.SplitN(parts[2], "-", 2)[0]
    52Ôćĺ		patch, _ = strconv.Atoi(patchStr)
    53Ôćĺ	}
    54Ôćĺ	return
    55Ôćĺ}
